1	const PROCESSING_FEE = 5;
2	
3	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
4	type Customer = { yearsWithMHPCO: number };
5	type QuoteStep = { op: "quote"; items: Item[] };
6	type Damage = { itemType: string; amount: number };
7	type Incident = { cause: string; damages: Damage[] };
8	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
9	type Step = QuoteStep | ClaimStep;
10	type Scenario = { customer: Customer; steps: Step[] };
11	type QuoteResult = { premium: number };
12	type ClaimResult = { payout: number; remainingCap: number };
13	type StepResult = QuoteResult | ClaimResult;
14	type ScenarioResult = { results: StepResult[] };
15	
16	type ItemSpec = { basePrice: number; insuranceValue: number };
17	
18	const ITEM_CATALOG: Record<string, ItemSpec> = {
19	  sword: { basePrice: 100, insuranceValue: 1000 },
20	  amulet: { basePrice: 60, insuranceValue: 600 },
21	  staff: { basePrice: 80, insuranceValue: 800 },
22	  potion: { basePrice: 40, insuranceValue: 400 },
23	  rune: { basePrice: 25, insuranceValue: 250 },
24	  moonstone: { basePrice: 25, insuranceValue: 250 },
25	};
26	
27	const specOf = (item: Item): ItemSpec | undefined => ITEM_CATALOG[item.type];
28	
29	const basePriceOf = (item: Item): number => specOf(item)?.basePrice ?? 0;
30	
31	const CURSED_SURCHARGE_RATE = 0.5;
32	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
33	const HIGH_ENCHANTMENT_THRESHOLD = 5;
34	
35	const enchantmentLevel = (item: Item): number => item.enchantment ?? 0;
36	
37	const isCursed = (item: Item): boolean => item.cursed === true;
38	const isHighlyEnchanted = (item: Item): boolean =>
39	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD;
40	
41	const surchargeRate = (item: Item): number =>
42	  (isCursed(item) ? CURSED_SURCHARGE_RATE : 0) +
43	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
44	
45	const itemSurchargeAmount = (item: Item): number =>
46	  basePriceOf(item) * surchargeRate(item);
47	
48	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
49	const BLOCK_SIZE = 3;
50	const BLOCK_PRICE = 60;
51	
52	const groupByType = (items: Item[]): Map<string, Item[]> =>
53	  items.reduce((groups, item) => {
54	    const existing = groups.get(item.type) ?? [];
55	    return groups.set(item.type, [...existing, item]);
56	  }, new Map<string, Item[]>());
57	
58	const qualifiesForComponentBlock = (type: string, members: Item[]): boolean =>
59	  COMPONENT_TYPES.has(type) && members.length === BLOCK_SIZE;
60	
61	const groupBasePremium = (type: string, members: Item[]): number => {
62	  if (qualifiesForComponentBlock(type, members)) return BLOCK_PRICE;
63	  return members.reduce((sum, item) => sum + basePriceOf(item), 0);
64	};
65	
66	const itemsBaseSubtotal = (items: Item[]): number =>
67	  Array.from(groupByType(items)).reduce(
68	    (total, [type, members]) => total + groupBasePremium(type, members),
69	    0,
70	  );
71	
72	const itemsSurchargeSubtotal = (items: Item[]): number =>
73	  items.reduce((sum, item) => sum + itemSurchargeAmount(item), 0);
74	
75	const LOYALTY_DISCOUNT_RATE = 0.2;
76	const LOYALTY_YEARS_THRESHOLD = 2;
77	
78	const isLoyalCustomer = (customer: Customer): boolean =>
79	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
80	
81	const loyaltyDiscountRate = (customer: Customer): number =>
82	  isLoyalCustomer(customer) ? LOYALTY_DISCOUNT_RATE : 0;
83	
84	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
85	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
86	
87	const hasPreviousContract = (stepIndex: number): boolean => stepIndex > 0;
88	
89	const followUpDiscountRate = (stepIndex: number): number =>
90	  hasPreviousContract(stepIndex) ? FOLLOW_UP_DISCOUNT_RATE : 0;
91	
92	const policyAdjustmentRate = (customer: Customer, stepIndex: number): number =>
93	  FIRST_INSURANCE_SURCHARGE_RATE -
94	  loyaltyDiscountRate(customer) -
95	  followUpDiscountRate(stepIndex);
96	
97	const quotePremium = (
98	  items: Item[],
99	  customer: Customer,
100	  stepIndex: number,
101	): number => {
102	  const baseSubtotal = itemsBaseSubtotal(items);
103	  const surchargeSubtotal = itemsSurchargeSubtotal(items);
104	  // Kept as `base + base*rate` (not `base*(1+rate)`) for IEEE-754 stability:
105	  // e.g. 100*(1+0.1) === 110.00000000000001, which trips Math.ceil rounding.
106	  return (
107	    baseSubtotal +
108	    baseSubtotal * policyAdjustmentRate(customer, stepIndex) +
109	    surchargeSubtotal +
110	    PROCESSING_FEE
111	  );
112	};
113	
114	// MHPCO always rounds in its own favor: premiums up, payouts down.
115	const roundPremiumInMhpcoFavor = (amount: number): number => Math.ceil(amount);
116	
117	const insuranceValueOf = (item: Item): number =>
118	  specOf(item)?.insuranceValue ?? 0;
119	
120	const DEDUCTIBLE_PER_DAMAGE = 100;
121	const CAP_MULTIPLIER = 2;
122	
123	const insuranceSum = (items: Item[]): number =>
124	  items.reduce((sum, item) => sum + insuranceValueOf(item), 0);
125	
126	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
127	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
128	
129	const isHighEnchantmentForPayout = (item: Item): boolean =>
130	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD;
131	
132	const reimbursableAmount = (damage: Damage, item: Item): number =>
133	  isHighEnchantmentForPayout(item)
134	    ? damage.amount * HIGH_ENCHANTMENT_PAYOUT_RATE
135	    : damage.amount;
136	
137	const damagePayout = (damage: Damage, item: Item): number =>
138	  reimbursableAmount(damage, item) - DEDUCTIBLE_PER_DAMAGE;
139	
140	// The CLI rejects claims for items not on the policy upstream, so the lookup
141	// is total over the inputs that reach this function.
142	const policyItemOfType = (policyItems: Item[], itemType: string): Item =>
143	  policyItems.find((item) => item.type === itemType) as Item;
144	
145	const totalPayout = (damages: Damage[], policyItems: Item[]): number =>
146	  damages.reduce(
147	    (sum, damage) =>
148	      sum + damagePayout(damage, policyItemOfType(policyItems, damage.itemType)),
149	    0,
150	  );
151	
152	const policyCap = (policyItems: Item[]): number =>
153	  CAP_MULTIPLIER * insuranceSum(policyItems);
154	
155	const runQuoteStep = (
156	  step: QuoteStep,
157	  customer: Customer,
158	  stepIndex: number,
159	): QuoteResult => ({
160	  premium: roundPremiumInMhpcoFavor(quotePremium(step.items, customer, stepIndex)),
161	});
162	
163	const runClaimStep = (step: ClaimStep, policyItems: Item[]): ClaimResult => {
164	  const payout = totalPayout(step.incident.damages, policyItems);
165	  return { payout, remainingCap: policyCap(policyItems) - payout };
166	};
167	
168	// Claim steps reference a prior quote step by index; the CLI guarantees that
169	// reference is valid and points at a quote, so the lookup is total.
170	const policyItemsAt = (steps: Step[], policyIndex: number): Item[] =>
171	  (steps[policyIndex] as QuoteStep).items;
172	
173	const runStep = (
174	  step: Step,
175	  customer: Customer,
176	  stepIndex: number,
177	  steps: Step[],
178	): StepResult =>
179	  step.op === "quote"
180	    ? runQuoteStep(step, customer, stepIndex)
181	    : runClaimStep(step, policyItemsAt(steps, step.policy));
182	
183	export const runScenario = (input: Scenario): ScenarioResult => ({
184	  results: input.steps.map((step, i) =>
185	    runStep(step, input.customer, i, input.steps),
186	  ),
187	});
